/****
 * =CQP_TOTAL_CLAIMS_TRANSIT + CQP_TOTAL_CLAIMS_STORAGE
 * By Adriana Centellas
 */

function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_TOTAL_CLAIMS_TRANSIT) + safeNumber(this.CQP_TOTAL_CLAIMS_STORAGE);

/*******
 * Enable/disable specific inputs when TYPE = "STP"
 * This calc only controls UI behavior (disabled state of fields)
 *
 * By Adriana Centellas
 *******/

// List of selectors for the fields you want to toggle
// Replace these with the real selector values of your fields
var selectorsToToggle = [
  'CQP_STORAGE_DISABLED'
];

// Flag to know if we are in STP mode
var isSTP = (this._parent.CQP_TYPE === 'CARGO');

// Use timeout so the DOM is ready when we search for the inputs
setTimeout(function () {
  selectorsToToggle.forEach(function (selectorName) {
    // Adjust this path if your structure is slightly different
    var $input = $('[selector="' + selectorName + '"] > div > input');

    // If the field is not found, skip it
    if (!$input.length) {
      return;
    }

    // Remove any previous custom disabled style class, if you want one
    $input.removeClass('inputDisabled');

    if (isSTP) {
      // Disable the input when TYPE = "STP"
      $input.prop('disabled', true);
      // Optional: add a CSS class if you want to style disabled differently
      $input.addClass('inputDisabled');
    } else {
      // Re-enable the input when TYPE is different from "STP"
      $input.prop('disabled', false);
    }
  });
}, 300);

// This calc is just for UI control; we can return null or 0
return null;

/******
 * =((CQP_TOTAL_CLAIMS_COMBINED/CQP_TOTAL_CLAIMS_COMBINED_HISTORICAL)-1)*100
 * By Adriana Centellas
 * Edited By Natalia Mendez
 */

// Convert any value to a safe number
function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

// Ensure numeric values
let totalClaimsCombined = safeNumber(this.CQP_TOTAL_CLAIMS_COMBINED);
let totalClaimsCombinedHistorical = safeNumber(this.CQP_TOTAL_CLAIMS_COMBINED_HISTORICAL);

// Main calculation
var returnVar = (totalClaimsCombinedHistorical !== 0 && totalClaimsCombined !== 0)
  ? ((totalClaimsCombined / totalClaimsCombinedHistorical) - 1) * 100
  : 0;

return returnVar;
